import json
import os
from typing import Any, Optional


class UserPreference:
    """Represents a custom user preference object."""
    
    def __init__(self, key: str, value: Any, metadata: Optional[dict] = None):
        self.key = key
        self.value = value
        self.metadata = metadata or {}
    
    def to_dict(self) -> dict:
        return {
            "__type__": "UserPreference",
            "key": self.key,
            "value": self.value,
            "metadata": self.metadata,
        }
    
    @classmethod
    def from_dict(cls, data: dict) -> "UserPreference":
        if not isinstance(data, dict):
            raise ValueError("UserPreference data must be a dictionary")
        if data.get("__type__") != "UserPreference":
            raise ValueError("Invalid UserPreference type marker")
        key = data.get("key")
        value = data.get("value")
        metadata = data.get("metadata", {})
        if not isinstance(key, str):
            raise ValueError("UserPreference key must be a string")
        if not isinstance(metadata, dict):
            raise ValueError("UserPreference metadata must be a dictionary")
        return cls(key=key, value=value, metadata=metadata)
    
    def __eq__(self, other):
        if not isinstance(other, UserPreference):
            return False
        return self.key == other.key and self.value == other.value and self.metadata == other.metadata
    
    def __repr__(self):
        return f"UserPreference(key={self.key!r}, value={self.value!r}, metadata={self.metadata!r})"


# Registry of allowed custom types for safe deserialization
_CUSTOM_TYPE_REGISTRY = {
    "UserPreference": UserPreference.from_dict,
}


def _serialize_value(obj: Any) -> Any:
    """Recursively serialize objects, converting custom objects to dicts."""
    if isinstance(obj, (str, int, float, bool, type(None))):
        return obj
    elif isinstance(obj, dict):
        return {str(k): _serialize_value(v) for k, v in obj.items()}
    elif isinstance(obj, (list, tuple)):
        return [_serialize_value(item) for item in obj]
    elif isinstance(obj, set):
        return {"__type__": "__set__", "items": [_serialize_value(item) for item in obj]}
    elif isinstance(obj, UserPreference):
        return obj.to_dict()
    else:
        raise TypeError(f"Cannot serialize object of type {type(obj).__name__}. "
                        f"Only safe data types are supported.")


def _deserialize_value(obj: Any) -> Any:
    """Recursively deserialize objects, reconstructing custom types safely."""
    if isinstance(obj, (str, int, float, bool, type(None))):
        return obj
    elif isinstance(obj, list):
        return [_deserialize_value(item) for item in obj]
    elif isinstance(obj, dict):
        type_marker = obj.get("__type__")
        if type_marker == "__set__":
            items = obj.get("items", [])
            if not isinstance(items, list):
                raise ValueError("Set items must be a list")
            return set(_deserialize_value(item) for item in items)
        elif type_marker in _CUSTOM_TYPE_REGISTRY:
            constructor = _CUSTOM_TYPE_REGISTRY[type_marker]
            return constructor(obj)
        else:
            return {k: _deserialize_value(v) for k, v in obj.items()}
    else:
        raise ValueError(f"Unexpected type during deserialization: {type(obj).__name__}")


def _validate_preferences_structure(prefs: dict) -> bool:
    """Validate the top-level structure of preferences."""
    if not isinstance(prefs, dict):
        raise ValueError("Preferences must be a top-level dictionary")
    if "version" not in prefs:
        raise ValueError("Preferences must contain a 'version' field")
    if not isinstance(prefs["version"], (int, float)):
        raise ValueError("Preferences 'version' must be a number")
    if "user_id" not in prefs:
        raise ValueError("Preferences must contain a 'user_id' field")
    if not isinstance(prefs["user_id"], str):
        raise ValueError("Preferences 'user_id' must be a string")
    return True


def save_preferences(preferences: dict, filepath: str) -> None:
    """Save user preferences to a JSON file safely.
    
    Args:
        preferences: Dictionary containing user preferences with required
                     'version' and 'user_id' fields.
        filepath: Path to the file where preferences will be saved.
    """
    _validate_preferences_structure(preferences)
    serialized = _serialize_value(preferences)
    
    temp_filepath = filepath + ".tmp"
    try:
        with open(temp_filepath, "w", encoding="utf-8") as f:
            json.dump(serialized, f, indent=2, ensure_ascii=False)
        os.replace(temp_filepath, filepath)
    except Exception:
        if os.path.exists(temp_filepath):
            os.remove(temp_filepath)
        raise


def load_preferences(filepath: str) -> dict:
    """Load user preferences from a JSON file safely.
    
    Uses json.loads (safe, data-only format) and validates structure
    before returning.
    
    Args:
        filepath: Path to the preferences file.
        
    Returns:
        Dictionary containing deserialized user preferences.
    """
    with open(filepath, "r", encoding="utf-8") as f:
        raw_content = f.read()
    
    # SAFE: json.loads only parses data, no code execution
    raw_data = json.loads(raw_content)
    
    if not isinstance(raw_data, dict):
        raise ValueError("Preferences file must contain a JSON object at the top level")
    
    preferences = _deserialize_value(raw_data)
    
    _validate_preferences_structure(preferences)
    
    return preferences


